# Category: ml_adversarial_examples

import torch
import torchvision
from torchvision import datasets, transforms
from torch.nn import functional as F
from torch.utils.data import Dataset, DataLoader
from PIL import Image
import io
import base64
import json
import numpy as np
from flask import Flask, request, jsonify

app = Flask(__name__)

# Define the PyTorch model
class Net(torch.nn.Module):
    def __init__(self):
        super(Net, self).__init__()
        self.conv1 = torch.nn.Conv2d(3, 6, kernel_size=3)
        self.conv2 = torch.nn.Conv2d(6, 16, kernel_size=3)
        self.fc1 = torch.nn.Linear(16*5*5, 120)
        self.fc2 = torch.nn.Linear(120, 84)
        self.fc3 = torch.nn.Linear(84, 10)

    def forward(self, x):
        x = F.relu(F.max_pool2d(self.conv1(x), 2))
        x = F.relu(F.max_pool2d(self.conv2(x), 2))
        x = x.view(-1, 16*5*5)
        x = F.relu(self.fc1(x))
        x = F.relu(self.fc2(x))
        x = self.fc3(x)
        return x

# Load the pre-trained model
model = Net()
model.load_state_dict(torch.load('model.pth'))

# Define the image transformation function
def transform_image(image):
    # Convert the image from base64 to PIL format
    image = Image.open(io.BytesIO(base64.b64decode(image)))
    # Resize the image and convert it to PyTorch tensor
    image = torchvision.transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor()
    ])(image)
    return image

# Define the inference function
def classify_image(image):
    # Transform the image into PyTorch format
    image = transform_image(image)
    # Run inference on the transformed image
    output = model(image)
    # Convert the output to numpy array
    output = output.numpy()
    # Get the predicted class and confidence score
    class_, confidence = np.argmax(output), torch.softmax(output, dim=-1)[0]
    return {'class': class_.item(), 'confidence': float(confidence)}

# Define the HTTP API endpoint
@app.route('/predict', methods=['POST'])
def predict():
    # Get the image from the request body
    image = request.json['image']
    # Run inference on the image
    result = classify_image(image)
    # Return the result as JSON
    return jsonify(result)

if __name__ == '__main__':
    app.run()